import{_ as s,o as i,c as t,ai as a}from"./chunks/framework.BZ-K7CQ_.js";const k=JSON.parse('{"title":"Installing on Windows","description":"","frontmatter":{"sidebar":true},"headers":[],"relativePath":"install-windows.md","filePath":"install-windows.md"}'),n={name:"install-windows.md"};function o(l,e,h,r,p,d){return i(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="installing-on-windows" tabindex="-1">Installing on Windows <a class="header-anchor" href="#installing-on-windows" aria-label="Permalink to “Installing on Windows”">​</a></h1><p>The Arcsecond CLI is a Python package, so installing it on Windows means making sure Python and <code>pip</code> are available, then letting <code>pip</code> drop the <code>arcsecond</code> executable somewhere Windows can find it. The default Windows setup gets in the way of all three of those steps, so this page walks through the common pitfalls in order.</p><p>If you are on macOS or Linux, see <a href="/cli/install">Install &amp; Login</a> instead.</p><h2 id="_1-install-python" tabindex="-1">1. Install Python <a class="header-anchor" href="#_1-install-python" aria-label="Permalink to “1. Install Python”">​</a></h2><p>You need a real Python interpreter. We recommend installing it from <a href="https://www.python.org/downloads/" target="_blank" rel="noreferrer">python.org/downloads</a> rather than the Microsoft Store: the python.org installer is more predictable, and the Store variant (&quot;Python install manager&quot;) has historically not added the scripts directory to <code>PATH</code> automatically.</p><p>When running the python.org installer, <strong>tick &quot;Add python.exe to PATH&quot;</strong> on the very first screen before clicking <em>Install Now</em>. That single checkbox is the cause of most &quot;<code>pip</code> is not recognized&quot; reports.</p><p>Open a <strong>new</strong> PowerShell window after the install (already-open terminals do not pick up <code>PATH</code> changes) and check:</p><div class="language-powershell"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">version</span></span></code></pre></div><p>You should get something like <code>Python 3.12.x</code>. If instead PowerShell opens the Microsoft Store, jump to <a href="#app-execution-aliases-when-python-opens-the-store">App execution aliases</a> below.</p><h2 id="_2-about-pip-and-pipx" tabindex="-1">2. About <code>pip</code> and <code>pipx</code> <a class="header-anchor" href="#_2-about-pip-and-pipx" aria-label="Permalink to “2. About pip and pipx”">​</a></h2><p>A common reflex on Windows is to install <code>pipx</code> first. <strong>For the Arcsecond CLI you do not need it.</strong> The package is small, has no conflicting dependencies, and is happy in your user <code>site-packages</code>.</p><ul><li>Use plain <code>pip</code> for Arcsecond — it ships with Python and is enough.</li><li>Use <code>pipx</code> only if you already use it for other Python CLIs and want Arcsecond isolated alongside them. In that case run <code>pipx install arcsecond</code>.</li><li>Do <strong>not</strong> mix the two on the same machine for the same tool. Pick one.</li></ul><p>If <code>pip</code> says it is out of date, that is fine; the upgrade notice from <code>pip</code> itself does not need to be acted on to install Arcsecond.</p><h2 id="_3-install-arcsecond" tabindex="-1">3. Install Arcsecond <a class="header-anchor" href="#_3-install-arcsecond" aria-label="Permalink to “3. Install Arcsecond”">​</a></h2><p>In the new PowerShell window:</p><div class="language-powershell"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m pip install </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">upgrade arcsecond</span></span></code></pre></div><p>We deliberately use <code>python -m pip</code> rather than the bare <code>pip</code> command: <code>python -m pip</code> always invokes the <code>pip</code> that belongs to the Python you just ran, which avoids ambiguity when several Pythons are installed.</p><p>If you see a long list of <code>Requirement already satisfied:</code> lines and no errors, the install succeeded.</p><h2 id="_4-verify-the-install" tabindex="-1">4. Verify the install <a class="header-anchor" href="#_4-verify-the-install" aria-label="Permalink to “4. Verify the install”">​</a></h2><div class="language-powershell"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">arcsecond </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">v</span></span></code></pre></div><p>If that prints a version number, you are done — head to <a href="/cli/install#authentication">Install &amp; Login</a> for the login step.</p><p>If instead you get:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>arcsecond : The term &#39;arcsecond&#39; is not recognized as the name of a</span></span>
<span class="line"><span>cmdlet, function, script file, or operable program.</span></span></code></pre></div><p>…then the install worked, but the directory where <code>pip</code> placed the <code>arcsecond.exe</code> entry point is not on <code>PATH</code>. Continue with <a href="#scripts-directory-not-on-path">Scripts directory not on PATH</a> below.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p><code>python -m arcsecond</code> does <strong>not</strong> work as a fallback. The package does not expose a <code>__main__.py</code>, so you will see <code>No module named arcsecond.__main__</code>. The fix is always to add the Scripts directory to <code>PATH</code>, not to invoke the module directly.</p></div><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to “Troubleshooting”">​</a></h2><h3 id="pip-is-not-recognized" tabindex="-1"><code>pip is not recognized</code> <a class="header-anchor" href="#pip-is-not-recognized" aria-label="Permalink to “pip is not recognized”">​</a></h3><p>Symptom:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>pip : The term &#39;pip&#39; is not recognized as the name of a cmdlet...</span></span>
<span class="line"><span>pipx : The term &#39;pipx&#39; is not recognized...</span></span>
<span class="line"><span>pip3 : The term &#39;pip3&#39; is not recognized...</span></span></code></pre></div><p>This means Python itself is not on <code>PATH</code>. Either Python is not installed, or it was installed without the &quot;Add python.exe to PATH&quot; checkbox.</p><p>Fix:</p><ol><li>Run <code>python --version</code> and <code>py --version</code> to see which (if any) is recognised.</li><li>If <code>py</code> works but <code>python</code> does not, use the launcher: <code>py -m pip install --upgrade arcsecond</code>.</li><li>If neither works, reinstall Python from <a href="https://www.python.org/downloads/" target="_blank" rel="noreferrer">python.org/downloads</a> and tick the PATH checkbox.</li><li>Always open a <strong>new</strong> PowerShell window after changing <code>PATH</code>.</li></ol><h3 id="app-execution-aliases-when-python-opens-the-store" tabindex="-1">App execution aliases (when <code>python</code> opens the Store) <a class="header-anchor" href="#app-execution-aliases-when-python-opens-the-store" aria-label="Permalink to “App execution aliases (when python opens the Store)”">​</a></h3><p>Windows ships stub executables for <code>python.exe</code> and <code>python3.exe</code> that redirect to the Microsoft Store. If you have a real Python installed, those stubs hide it.</p><p>Disable them:</p><ol><li>Open <em>Settings → Apps → Advanced app settings → App execution aliases</em>.</li><li>Turn <strong>off</strong> the toggles for <code>python.exe</code> and <code>python3.exe</code> (and <code>Python (default)</code> if present).</li><li>Close PowerShell and open a new window.</li></ol><p><code>python --version</code> should now show your real interpreter.</p><h3 id="scripts-directory-not-on-path" tabindex="-1">Scripts directory not on <code>PATH</code> <a class="header-anchor" href="#scripts-directory-not-on-path" aria-label="Permalink to “Scripts directory not on PATH”">​</a></h3><p>Symptom: <code>python -m pip install arcsecond</code> succeeds, but <code>arcsecond -v</code> returns <code>CommandNotFoundException</code>.</p><p>This is common with the Microsoft Store &quot;Python install manager&quot; variant, which installs into <code>C:\\Users\\&lt;you&gt;\\AppData\\Local\\Python\\PythonCore-&lt;version&gt;\\</code> and does not put the matching <code>Scripts\\</code> folder on <code>PATH</code>.</p><p><strong>Step 1 — find the exact Scripts path:</strong></p><div class="language-powershell"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;import sysconfig; print(sysconfig.get_path(&#39;scripts&#39;))&quot;</span></span></code></pre></div><p>This prints the directory where <code>pip</code> installs console-script executables. Example output:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>C:\\Users\\WEO\\AppData\\Local\\Python\\PythonCore-3.14-64\\Scripts</span></span></code></pre></div><p><strong>Step 2 — confirm <code>arcsecond.exe</code> is actually there:</strong></p><div class="language-powershell"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dir </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;paste-the-path&gt;\\arcsecond*&quot;</span></span></code></pre></div><p>You should see <code>arcsecond.exe</code>. If you do not, the entry point was not installed; reinstall with:</p><div class="language-powershell"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m pip install </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">force</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">reinstall arcsecond</span></span></code></pre></div><p><strong>Step 3 — sanity-check by running the full path:</strong></p><div class="language-powershell"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;&lt;paste-the-path&gt;\\arcsecond.exe&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">v</span></span></code></pre></div><p>If that prints a version, the install is fine — only <code>PATH</code> is wrong.</p><p><strong>Step 4 — add the Scripts directory to <code>PATH</code> permanently:</strong></p><div class="language-powershell"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$scripts </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;import sysconfig; print(sysconfig.get_path(&#39;scripts&#39;))&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$current </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Environment</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]::GetEnvironmentVariable(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Path&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;User&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Environment</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]::SetEnvironmentVariable(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Path&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$current</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$scripts</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;User&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Close PowerShell completely and open a fresh window. <code>arcsecond -v</code> should now work.</p><p>If you prefer the GUI: <em>Settings → System → About → Advanced system settings → Environment Variables</em>, edit your user <code>Path</code>, and add the Scripts folder as a new entry.</p><h3 id="no-module-named-arcsecond-main" tabindex="-1"><code>No module named arcsecond.__main__</code> <a class="header-anchor" href="#no-module-named-arcsecond-main" aria-label="Permalink to “No module named arcsecond.__main__”">​</a></h3><p>You ran <code>python -m arcsecond</code>. That is not how Arcsecond is invoked — it ships as a console script (<code>arcsecond.exe</code>), not as a runnable module. Fix <code>PATH</code> as described above and call <code>arcsecond</code> directly.</p><h3 id="powershell-execution-policy-errors" tabindex="-1">PowerShell execution-policy errors <a class="header-anchor" href="#powershell-execution-policy-errors" aria-label="Permalink to “PowerShell execution-policy errors”">​</a></h3><p>If PowerShell refuses to run scripts at all (red text about execution policy), open <em>PowerShell as Administrator</em> and run:</p><div class="language-powershell"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Set-ExecutionPolicy</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Scope CurrentUser </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ExecutionPolicy RemoteSigned</span></span></code></pre></div><p>Then reopen a normal PowerShell window.</p><h2 id="once-it-works" tabindex="-1">Once it works <a class="header-anchor" href="#once-it-works" aria-label="Permalink to “Once it works”">​</a></h2><p>Continue with <a href="/cli/install#authentication">Authentication</a> to log in with your Access or Upload Key.</p>`,63)])])}const g=s(n,[["render",o]]);export{k as __pageData,g as default};
